def validate_interpolation_domain(model_x: Any, benchmark_x: Any) -> Dict[str, Any]:
    model_x_arr = _to_1d_float_array(model_x, "model_x")
    benchmark_x_arr = _to_1d_float_array(benchmark_x, "benchmark_x")
    model_min, model_max = float(np.min(model_x_arr)), float(np.max(model_x_arr))
    bench_min, bench_max = float(np.min(benchmark_x_arr)), float(np.max(benchmark_x_arr))
    overlap_min = max(model_min, bench_min)
    overlap_max = min(model_max, bench_max)
    has_overlap = overlap_max > overlap_min
    mask = (benchmark_x_arr >= overlap_min) & (benchmark_x_arr <= overlap_max) if has_overlap else np.zeros_like(benchmark_x_arr, dtype=bool)
    overlap_ratio = float(np.mean(mask)) if benchmark_x_arr.size else 0.0
    return {
        "has_overlap": has_overlap,
        "mask": mask,
        "model_range": (model_min, model_max),
        "benchmark_range": (bench_min, bench_max),
        "overlap_range": (overlap_min, overlap_max),
        "overlap_ratio": overlap_ratio,
        "used_extrapolation": bool(np.any(~mask)) if has_overlap else True,
    }



def monte_carlo_uncertainty_analysis_parallel(
    prediction: Any,
    benchmark_y: Any,
    n_simulations: int = 10000,
    n_workers: Optional[int] = None,
) -> Dict[str, Any]:
    """
    FIX 6 (v6.1): Parallelized Monte Carlo UQ.
    joblib.Parallel orqali CPU corelarni to'liq ishlatish.
    Katta datasetlarda RAM va vaqt tejaladi.
    """
    pred = _to_1d_float_array(prediction, "prediction")
    bench = _to_1d_float_array(benchmark_y, "benchmark_y")
    residuals = pred - bench
    noise_scale = max(float(np.std(residuals, ddof=1)) if residuals.size > 1 else 0.0, EPS_GENERAL)
    n_sim = clamp_mc_samples(max(10000, int(n_simulations)),
                            label="monte_carlo_uncertainty_analysis_parallel.n_simulations")

    try:
        from joblib import Parallel, delayed
        n_workers = n_workers or max(1, multiprocessing.cpu_count() - 1)
        chunk_size = max(1000, n_sim // n_workers)

        def _mc_chunk(n: int, seed: int) -> np.ndarray:
            rng = np.random.default_rng(seed=seed)
            return pred[None, :] + rng.normal(0.0, noise_scale, size=(n, pred.size))

        chunks = [(chunk_size, RANDOM_SEED + i) for i in range(n_sim // chunk_size)]
        remainder = n_sim % chunk_size
        if remainder > 0:
            chunks.append((remainder, RANDOM_SEED + len(chunks)))

        samples_list = Parallel(n_jobs=n_workers, backend="loky")(
            delayed(_mc_chunk)(n, s) for n, s in chunks
        )
        samples = np.vstack(samples_list)
        logger.info(f"Parallel MC: {n_sim} simulations with {n_workers} workers")
    except ImportError:
        # Fallback: sequential
        # ISS-N07 FIX: modul darajasidagi rng_global ishlatish oqim-xavfsiz emas
        # (ProcessPoolExecutor/Streamlit ko'p oqimida race condition).
        # Mahalliy RNG namunasi ishlatamiz — takrorlanuvchan va oqim-xavfsiz.
        _rng_seq = np.random.default_rng(seed=RANDOM_SEED)
        samples = pred[None, :] + _rng_seq.normal(0.0, noise_scale, size=(n_sim, pred.size))
        logger.info(f"Sequential MC: {n_sim} simulations (joblib not available)")

    error_samples = samples - bench[None, :]
    return {
        "n_simulations": n_sim,
        "prediction_mean": np.mean(samples, axis=0),
        "prediction_std": np.std(samples, axis=0),
        "error_samples": error_samples,
        "ci95": (np.percentile(samples, 2.5, axis=0), np.percentile(samples, 97.5, axis=0)),
        "ci99": (np.percentile(samples, 0.5, axis=0), np.percentile(samples, 99.5, axis=0)),
    }


# ── FIX 36-40: Monte Carlo with 10000 samples, LHS, Sobol, FAST, Bayesian ──
def monte_carlo_uncertainty_analysis(
    prediction: Any,
    benchmark_y: Any,
    n_simulations: int = 10000,  # FIX 36: increased from 1500 to 10000
) -> Dict[str, Any]:
    pred = _to_1d_float_array(prediction, "prediction")
    bench = _to_1d_float_array(benchmark_y, "benchmark_y")
    residuals = pred - bench
    noise_scale = max(float(np.std(residuals, ddof=1)) if residuals.size > 1 else 0.0, EPS_GENERAL)
    # FIX #4: clamp n_simulations to [10000, MAX_MC_SAMPLES] to prevent RAM blowup
    n_sim = clamp_mc_samples(max(10000, int(n_simulations)), label="monte_carlo_uncertainty_analysis.n_simulations")

    # FIX #46: chunked computation to avoid RAM blowup on large `pred.size`.
    # The original code allocated ``samples`` as a single (n_sim, pred.size)
    # ndarray. When pred.size is large (e.g. 10 000 grid points) and n_sim is
    # 100 000, this is 8 GB of float64 — far too much for a typical laptop.
    # We split the simulations into chunks of at most ~10 M elements each and
    # accumulate statistics incrementally (mean, std, percentiles via
    # streaming histogram is overkill — we keep two-pass accumulation for
    # CI bounds using a partial array).
    MAX_ELEMENTS_PER_CHUNK = 10_000_000  # 10M float64 ≈ 80 MB
    chunk_size = max(1, MAX_ELEMENTS_PER_CHUNK // max(1, pred.size))

    # Streaming accumulators for mean & variance (Welford-style, batched)
    running_mean = np.zeros_like(pred, dtype=float)
    running_M2 = np.zeros_like(pred, dtype=float)
    total_n = 0

    # We still need error_samples for the result; keep a single representative
    # chunk (the last one) for backward compatibility.
    error_samples_last = None
    samples_last = None
    # ISS-N07 FIX: modul darajasidagi rng_global ishlatish oqim-xavfsiz emas.
    # Mahalliy RNG — takrorlanuvchan va race-condition dan xoli.
    _rng_local = np.random.default_rng(seed=RANDOM_SEED)

    for chunk_start in range(0, n_sim, chunk_size):
        chunk_n = min(chunk_size, n_sim - chunk_start)
        chunk = pred[None, :] + _rng_local.normal(0.0, noise_scale, size=(chunk_n, pred.size))
        # Update streaming statistics (batched Welford)
        batch_mean = chunk.mean(axis=0)
        batch_var = chunk.var(axis=0, ddof=0)
        if total_n == 0:
            running_mean = batch_mean.copy()
            running_M2 = batch_var * chunk_n
        else:
            delta = batch_mean - running_mean
            new_total = total_n + chunk_n
            running_mean = running_mean + delta * (chunk_n / new_total)
            running_M2 = running_M2 + batch_var * chunk_n + (delta ** 2) * (total_n * chunk_n / new_total)
        total_n += chunk_n
        samples_last = chunk
        error_samples_last = chunk - bench[None, :]

    # Final statistics
    if total_n > 1:
        prediction_std = np.sqrt(running_M2 / (total_n - 1))
    else:
        prediction_std = np.zeros_like(pred, dtype=float)

    # BUG-02/BUG-09 FIX (v7.8): CI computed from analytical formula using streaming
    # variance, NOT from the last chunk (which is biased). Also correctly labels
    # these as "95% CI of mean" vs "95% prediction interval" (distribution percentiles).
    # For distribution percentiles, we use mean ± 1.96*std (normal approximation).
    ci95_mean_low = running_mean - 1.96 * prediction_std / np.sqrt(max(total_n, 1))
    ci95_mean_high = running_mean + 1.96 * prediction_std / np.sqrt(max(total_n, 1))
    # 95% prediction interval (distribution P2.5/P97.5 via normal approx)
    ci95_pred_low = running_mean - 1.96 * prediction_std
    ci95_pred_high = running_mean + 1.96 * prediction_std
    # 99% prediction interval
    ci99_pred_low = running_mean - 2.576 * prediction_std
    ci99_pred_high = running_mean + 2.576 * prediction_std

    return {
        "n_simulations": n_sim,
        "prediction_mean": running_mean,
        "prediction_std": prediction_std,
        "error_samples": error_samples_last if error_samples_last is not None else np.zeros((1, pred.size)),
        "ci95_mean": (ci95_mean_low, ci95_mean_high),  # 95% CI of the MEAN
        "ci95_prediction": (ci95_pred_low, ci95_pred_high),  # 95% prediction interval (P2.5-P97.5)
        "ci99_prediction": (ci99_pred_low, ci99_pred_high),  # 99% prediction interval
        # Backward-compatible keys (mapped to prediction intervals, NOT mean CI)
        "ci95": (ci95_pred_low, ci95_pred_high),
        "ci99": (ci99_pred_low, ci99_pred_high),
    }


# ── FIX 37: Latin Hypercube Sampling ────────────────────────────────
def latin_hypercube_sampling(problem: Dict, n_samples: int = 10000) -> np.ndarray:
    """Latin Hypercube Sampling (FIX 37)"""
    if PYDOE_AVAILABLE:
        return lhs(problem["num_vars"], samples=n_samples)
    else:
        # Fallback to random sampling
        logger.warning("pyDOE not available, using random sampling for LHS fallback")
        arr = np.random.rand(n_samples, problem["num_vars"])
        for i, (low, high) in enumerate(problem["bounds"]):
            arr[:, i] = low + arr[:, i] * (high - low)
        return arr


# ── FIX 38: Sobol Analysis ───────────────────────────────────────────
def sobol_analysis(problem: Dict, func: Callable, n_samples: int = 10000) -> Dict[str, Any]:
    """Sobol sensitivity analysis (FIX 38)"""
    if not SALIB_AVAILABLE:
        raise ImportError(tr("err.salib_not_installed"))
    param_values = saltelli.sample(problem, n_samples, calc_second_order=True)
    Y = np.array([func(p) for p in param_values])
    Si = sobol.analyze(problem, Y, calc_second_order=True)
    return {
        "method": "sobol",
        "S1": {name: float(val) for name, val in zip(problem["names"], Si["S1"])},
        "S1_conf": {name: float(val) for name, val in zip(problem["names"], Si["S1_conf"])},
        "ST": {name: float(val) for name, val in zip(problem["names"], Si["ST"])},
        "ST_conf": {name: float(val) for name, val in zip(problem["names"], Si["ST_conf"])},
        "S2": Si.get("S2", None),
        "S2_conf": Si.get("S2_conf", None),
    }


# ── FIX 39: FAST Analysis ────────────────────────────────────────────
def fast_analysis(problem: Dict, func: Callable, n_samples: int = 10000) -> Dict[str, Any]:
    """FAST (Fourier Amplitude Sensitivity Test) analysis (FIX 39)"""
    if not SALIB_AVAILABLE:
        raise ImportError(tr("err.salib_not_installed"))
    param_values = fast.sample(problem, n_samples)
    Y = np.array([func(p) for p in param_values])
    Si = fast.analyze(problem, Y)
    return {
        "method": "fast",
        "S1": {name: float(val) for name, val in zip(problem["names"], Si["S1"])},
    }


# ── FIX 40: Bayesian Uncertainty Quantification ──────────────────────

def bayesian_uq_nuts(prior_mean: np.ndarray, prior_cov: np.ndarray,
                     likelihood_func: Callable, data: np.ndarray,
                     n_samples: int = 10000, n_tune: int = 2000) -> Dict[str, Any]:
    """
    FIX 7 (v6.1): Bayesian UQ with PyMC/NUTS sampler.
    PyMC mavjud bo'lmasa, improved Metropolis-Hastings bilan ishlaydi.
    """
    # Try PyMC first (NUTS sampler — gold standard)
    try:
        import pymc as pm
        import arviz as az

        n_params = len(prior_mean)
        with pm.Model() as model:
            # Prior
            theta = pm.MvNormal("theta", mu=prior_mean, cov=prior_cov, shape=n_params)
            # Likelihood (custom)
            pm.Potential("likelihood", likelihood_func(theta, data))
            # NUTS sampler
            trace = pm.sample(draws=n_samples, tune=n_tune, chains=4, cores=max(1, multiprocessing.cpu_count() - 1),
                              random_seed=RANDOM_SEED, return_inferencedata=True)

        summary = az.summary(trace)
        samples_array = trace.posterior["theta"].values.reshape(-1, n_params)

        return {
            "samples": samples_array,
            "mean": np.mean(samples_array, axis=0),
            "std": np.std(samples_array, axis=0),
            "ci95_low": np.percentile(samples_array, 2.5, axis=0),
            "ci95_high": np.percentile(samples_array, 97.5, axis=0),
            "acceptance_rate": float(summary.get("ess_bulk", [0])[0]) if "ess_bulk" in summary else 0.0,
            "n_samples": len(samples_array),
            "sampler": "PyMC_NUTS",
            "r_hat": float(summary.get("r_hat", [1.0])[0]) if "r_hat" in summary else 1.0,
            "ess_bulk": float(summary.get("ess_bulk", [0])[0]) if "ess_bulk" in summary else 0.0,
        }
    except ImportError:
        logger.warning("PyMC not available. Using improved Metropolis-Hastings with adaptive step size.")
    except Exception as exc:
        logger.warning(f"PyMC sampling failed: {exc}. Falling back to improved MH.")

    # Improved Metropolis-Hastings with adaptive step size
    rng = np.random.default_rng(seed=RANDOM_SEED)
    n_params = len(prior_mean)
    samples = np.zeros((n_samples, n_params))
    current = prior_mean.copy().astype(float)
    current_log_lik = likelihood_func(current, data)
    accepted = 0
    step_scale = 0.1

    # Adaptive step size (Robbins-Monro)
    target_acceptance = 0.234  # Optimal for MH (Roberts et al., 1997)
    for i in range(n_samples):
        # Adaptive proposal
        proposal_cov = prior_cov * step_scale
        proposal = rng.multivariate_normal(current, proposal_cov)
        proposal_log_lik = likelihood_func(proposal, data)
        log_ratio = proposal_log_lik - current_log_lik
        if log_ratio > np.log(rng.random()):
            current = proposal
            current_log_lik = proposal_log_lik
            accepted += 1
        samples[i, :] = current
        # Adapt step size every 100 iterations
        if (i + 1) % 100 == 0 and i > 0:
            current_rate = accepted / (i + 1)
            step_scale *= np.exp(0.5 * (current_rate - target_acceptance))
            step_scale = np.clip(step_scale, 1e-6, 10.0)

    # Compute R-hat (Gelman-Rubin) if we have enough samples
    def compute_rhat(chain, n_splits=2):
        split_chains = np.array_split(chain, n_splits)
        chain_means = [np.mean(c, axis=0) for c in split_chains]
        chain_vars = [np.var(c, axis=0, ddof=1) for c in split_chains]
        W = np.mean(chain_vars, axis=0)
        B = np.var(chain_means, axis=0, ddof=1) * len(split_chains[0])
        var_hat = (1 - 1/len(split_chains[0])) * W + B / len(split_chains[0])
        rhat = np.sqrt(var_hat / (W + 1e-12))
        return float(np.mean(rhat))

    rhat = compute_rhat(samples)

    return {
        "samples": samples,
        "mean": np.mean(samples, axis=0),
        "std": np.std(samples, axis=0),
        "ci95_low": np.percentile(samples, 2.5, axis=0),
        "ci95_high": np.percentile(samples, 97.5, axis=0),
        "acceptance_rate": accepted / n_samples,
        "n_samples": n_samples,
        "sampler": "Adaptive_Metropolis_Hastings",
        "r_hat": rhat,
        "step_scale_final": step_scale,
    }

# Old MH implementation replaced by bayesian_uq_nuts above


def calculate_validation_score(metrics: ExperimentalMetrics, observed_span: float) -> float:
    span = max(float(observed_span), EPS_GENERAL)
    rmse_norm = float(np.clip(metrics.rmse / span, 0.0, 1.0))
    mae_norm = float(np.clip(metrics.mae / span, 0.0, 1.0))
    return float(
        (
            0.30 * max(metrics.r2, 0.0)
            + 0.20 * max(metrics.nse, 0.0)
            + 0.20 * max(metrics.kge, 0.0)
            + 0.15 * (1.0 - rmse_norm)
            + 0.15 * (1.0 - mae_norm)
        ) * 100.0
    )


def perform_validation_sensitivity_analysis(
    model_x: Any,
    model_y: Any,
    benchmark_x: Any,
    benchmark_y: Any,
    base_params: Optional[Dict[str, float]] = None,
) -> pd.DataFrame:
    base_params = base_params or {
        "Depth": 1.0,
        "Panel Width": 1.0,
        "Rock Strength": 1.0,
        "Temperature": 1.0,
    }
    model_x_arr = _to_1d_float_array(model_x, "model_x")
    model_y_arr = _to_1d_float_array(model_y, "model_y")
    benchmark_x_arr = _to_1d_float_array(benchmark_x, "benchmark_x")
    benchmark_y_arr = _to_1d_float_array(benchmark_y, "benchmark_y")

    def transform_curve(name: str, delta: float) -> np.ndarray:
        if name == "Depth":
            return model_y_arr * (1.0 + 0.12 * delta)
        if name == "Panel Width":
            x_scaled = model_x_arr * (1.0 + 0.08 * delta)
            return _align_prediction_to_reference(model_y_arr, x_scaled, model_x_arr, "model_x")
        if name == "Rock Strength":
            return model_y_arr * (1.0 - 0.10 * delta)
        if name == "Temperature":
            return model_y_arr * (1.0 + 0.06 * delta)
        return model_y_arr

    base_metrics = calculate_comparison_metrics(model_x_arr, model_y_arr, benchmark_x_arr, benchmark_y_arr, n_simulations=10000)
    rows = []
    for param in base_params.keys():
        minus_metrics = calculate_comparison_metrics(model_x_arr, transform_curve(param, -1.0), benchmark_x_arr, benchmark_y_arr, n_simulations=10000)
        plus_metrics = calculate_comparison_metrics(model_x_arr, transform_curve(param, 1.0), benchmark_x_arr, benchmark_y_arr, n_simulations=10000)
        sensitivity_score = 0.5 * (
            abs(plus_metrics["score"] - base_metrics["score"])
            + abs(minus_metrics["score"] - base_metrics["score"])
        )
        rows.append({
            "Parameter": param,
            "Base": base_params[param],
            "SensitivityScore": float(sensitivity_score),
            "PlusScore": float(plus_metrics["score"]),
            "MinusScore": float(minus_metrics["score"]),
        })
    return pd.DataFrame(rows).sort_values("SensitivityScore", ascending=False)


# ── FIX 41-43: Reproducibility snapshot with versioning ─────────────
def create_reproducibility_snapshot(
    model_x: Any,
    model_y: Any,
    benchmark_payload: Dict[str, Any],
    metrics: Dict[str, Any],
    context: Optional[Dict[str, Any]] = None,
    dataset_version: Optional[DatasetVersion] = None,
    model_version: Optional[ModelVersion] = None,
    experiment_version: Optional[ExperimentVersion] = None,
) -> Dict[str, Any]:
    snapshot = {
        "version": __version__,
        "git_commit": __git_commit__,
        "timestamp_utc": datetime.utcnow().strftime("%Y-%m-%dT%H:%M:%SZ"),
        "model_hash": _array_hash(
            _to_1d_float_array(model_x, "model_x").reshape(-1, 1),
            _to_1d_float_array(model_y, "model_y").reshape(-1, 1),
        ),
        "benchmark_hash": _array_hash(
            _to_1d_float_array(benchmark_payload["x"], "benchmark_x").reshape(-1, 1),
            _to_1d_float_array(benchmark_payload["subsidence_cm"], "benchmark_y").reshape(-1, 1),
        ),
        "benchmark_name": benchmark_payload.get("benchmark_name", benchmark_payload.get("source_type", "benchmark")),
        "source_path": benchmark_payload.get("source_path"),
        "unit_detected": benchmark_payload.get("unit_detected", "cm"),
        "software_version": benchmark_payload.get("software_version"),
        "export_date": benchmark_payload.get("export_date"),
        "metrics": {
            "rmse": float(metrics["rmse"]),
            "mae": float(metrics["mae"]),
            "r2": float(metrics["r2"]),
            "nse": float(metrics["nse"]),
            "kge": float(metrics["kge"]),
            "score": float(metrics["score"]),
        },
        "context": context or {},
    }
    # FIX 41-43: Add versioning info
    if dataset_version is not None:
        snapshot["dataset_version"] = asdict(dataset_version)
    if model_version is not None:
        snapshot["model_version"] = asdict(model_version)
    if experiment_version is not None:
        snapshot["experiment_version"] = asdict(experiment_version)
    
    snapshot["input_hash"] = hashlib.sha256(
        json.dumps(snapshot, sort_keys=True, default=_json_default_serializer).encode("utf-8")
    ).hexdigest()
    return snapshot


def save_reproducibility_snapshot(snapshot: Dict[str, Any], base_dir: str = DEFAULT_REPORT_DIR) -> str:
    filename = safe_filepath(f"validation_snapshot_{snapshot['input_hash'][:12]}.json", base_dir=base_dir)
    with open(filename, "w", encoding="utf-8") as f:
        json.dump(snapshot, f, ensure_ascii=False, indent=2, default=_json_default_serializer)
    return filename


# ── FIX 44: environment.yml export ─────────────────────────────────
def export_environment_yml(base_dir: str = DEFAULT_REPORT_DIR) -> str:
    """Export conda environment to environment.yml (FIX 44)"""
    env_path = Path(base_dir) / "environment.yml"
    env_path.parent.mkdir(parents=True, exist_ok=True)
    try:
        import subprocess as sp
        result = sp.run(["conda", "env", "export", "--no-builds"], capture_output=True, text=True)
        with open(env_path, "w") as f:
            f.write(result.stdout)
        return str(env_path)
    except Exception as e:
        logger.warning(f"Could not export environment: {e}")
        return ""


# ── FIX 45: pip freeze hash ─────────────────────────────────────────

class EnvironmentVerifier:
    """
    FIX 14 (v6.1): Environment verification.
    - requirements.txt hash tekshiruvi
    - Python versiya tekshiruvi
    - Kerakli paketlar mavjudligi
    - Git commit tekshiruvi
    """

    REQUIRED_PACKAGES = [
        "numpy", "pandas", "scipy", "sklearn", "streamlit",
        "plotly", "matplotlib", "cryptography", "reportlab",
    ]

    @classmethod
    def verify(cls) -> Dict[str, Any]:
        result = {
            "python_version": platform.python_version(),
            "platform": platform.platform(),
            "timestamp": datetime.utcnow().isoformat(),
        }

        # requirements.txt hash
        req_hash = "not_found"
        for req_path in ["requirements.txt", "../requirements.txt", "../../requirements.txt"]:
            if Path(req_path).exists():
                with open(req_path, "rb") as f:
                    req_hash = hashlib.sha256(f.read()).hexdigest()
                break
        result["requirements_hash"] = req_hash

        # Package availability
        missing = []
        available = []
        for pkg in cls.REQUIRED_PACKAGES:
            try:
                mod = __import__(pkg)
                version = getattr(mod, "__version__", "unknown")
                available.append({"name": pkg, "version": version})
            except ImportError:
                missing.append(pkg)
        result["available_packages"] = available
        result["missing_packages"] = missing
        result["all_required_available"] = len(missing) == 0

        # pip freeze hash
        result["pip_freeze_hash"] = get_pip_freeze_hash()
        # FIX: alias for backward compatibility with TestPatentV6Full which
        # checks for "packages_hash" key.
        result["packages_hash"] = result["pip_freeze_hash"]

        # Git commit
        result["git_commit"] = __git_commit__

        return result


def get_pip_freeze_hash() -> str:
    """Get hash of pip freeze output (FIX 45)"""
    try:
        import subprocess as sp
        result = sp.run(["pip", "freeze"], capture_output=True, text=True)
        return hashlib.sha256(result.stdout.encode()).hexdigest()
    except Exception:
        return "unknown"


def build_benchmark_ranking(results: List[BenchmarkResult], historical: Optional[pd.DataFrame] = None) -> pd.DataFrame:
    rows = [
        {
            "Benchmark": res.model_name,
            "Validation Score": float(res.validation_score),
            "RMSE": float(res.rmse),
            "MAE": float(res.mae),
            "R²": float(res.r2),
            "NSE": float(res.nse),
            "KGE": float(res.kge),
            "Source": res.source_type,
            "Version": res.software_version or "N/A",
            "Export Date": res.export_date or "N/A",
            "Bias": float(res.bias),
            "Relative RMSE": float(res.relative_rmse),
        }
        for res in results
    ]
    if historical is not None and not historical.empty:
        rows.extend(historical.to_dict("records"))
    ranking_df = pd.DataFrame(rows)
    if ranking_df.empty:
        return pd.DataFrame(columns=["Rank", "Benchmark", "Validation Score", "RMSE", "MAE", "R²", "NSE", "KGE", "Source", "Version", "Export Date", "Bias", "Relative RMSE"])
    ranking_df = ranking_df.sort_values("Validation Score", ascending=False).drop_duplicates(subset=["Benchmark", "Source"], keep="first")
    ranking_df.insert(0, "Rank", np.arange(1, len(ranking_df) + 1))
    return ranking_df.reset_index(drop=True)


