class DatabaseBackupManager:
    """
    FIX 19 (v6.1): Database Backup Manager.
    - auto_backup() funksiyasi
    - Backup fayllar versiyalanadi
    - Compressed (gzip) backuplar
    - Max backup soni cheklovi
    - Restore imkoniyati
    """

    BACKUP_DIR = Path(os.getenv("UCG_BACKUP_DIR", Path.home() / ".ucg_platform" / "backups"))
    MAX_BACKUPS = int(os.getenv("UCG_MAX_BACKUPS", "10"))

    def __init__(self, db_path: str = PATENT_AUDIT_DB):
        self.db_path = db_path
        self.backup_dir = self.BACKUP_DIR
        self.backup_dir.mkdir(parents=True, exist_ok=True)

    def auto_backup(self) -> str:
        """Avtomatik backup yaratish."""
        import gzip
        timestamp = datetime.utcnow().strftime("%Y%m%dT%H%M%S")
        db_file = Path(self.db_path)
        if not db_file.exists():
            logger.warning(f"Database file not found: {self.db_path}")
            return ""

        backup_filename = f"{db_file.stem}_backup_{timestamp}.db.gz"
        backup_path = self.backup_dir / backup_filename

        # Create compressed backup
        with open(db_file, "rb") as f_in:
            with gzip.open(backup_path, "wb") as f_out:
                f_out.write(f_in.read())

        logger.info(f"Database backup created: {backup_path}")

        # Cleanup old backups
        self._cleanup_old_backups()

        return str(backup_path)

    def _cleanup_old_backups(self):
        """Eski backuplarni o'chirish (MAX_BACKUPS dan ko'p bo'lsa)."""
        backups = sorted(self.backup_dir.glob("*.db.gz"), key=lambda p: p.stat().st_mtime, reverse=True)
        for old_backup in backups[self.MAX_BACKUPS:]:
            old_backup.unlink()
            logger.info(f"Removed old backup: {old_backup}")

    def restore_backup(self, backup_path: str) -> bool:
        """Backupdan bazani tiklash."""
        import gzip
        backup = Path(backup_path)
        if not backup.exists():
            logger.error(f"Backup file not found: {backup_path}")
            return False
        try:
            with gzip.open(backup, "rb") as f_in:
                with open(self.db_path, "wb") as f_out:
                    f_out.write(f_in.read())
            logger.info(f"Database restored from: {backup_path}")
            return True
        except Exception as exc:
            logger.error(f"Restore failed: {exc}")
            return False

    def list_backups(self) -> List[Dict[str, Any]]:
        """Mavjud backuplar ro'yxati."""
        backups = []
        for f in sorted(self.backup_dir.glob("*.db.gz"), reverse=True):
            stat = f.stat()
            backups.append({
                "filename": f.name,
                "size_mb": round(stat.st_size / 1024 / 1024, 2),
                "created": datetime.fromtimestamp(stat.st_mtime).isoformat(),
            })
        return backups



class SemanticBenchmarkRunner:
    """
    FIX 20 (v6.1): Semantic Novelty Benchmark.
    SciBERT, PatentSBERTa, SentenceTransformer modellarini
    solishtirib, benchmark report chiqarish.
    """

    MODELS_TO_TEST = [
        {"name": "allenai/scibert_scivocab_uncased", "type": "scibert"},
        {"name": "AI-Growth/PatentSBERTa", "type": "patent_sberta"},
        {"name": "all-MiniLM-L6-v2", "type": "sentence_transformer"},
        {"name": "tfidf_fallback", "type": "baseline"},
    ]

    @classmethod
    def run_benchmark(cls, invention_text: str = "Adaptive Biot coefficient with thermal degradation for UCG monitoring",
                       prior_art_texts: Optional[List[str]] = None) -> Dict[str, Any]:
        """Barcha modellarni benchmark qilish."""
        if prior_art_texts is None:
            prior_art_texts = [
                "Biot consolidation theory for saturated soils",
                "Poroelasticity and effective stress principle",
                "Thermal degradation of rock mass strength",
                "UCG cavity stability analysis",
                "Monte Carlo uncertainty quantification in geomechanics",
            ]

        results = {}
        for model_spec in cls.MODELS_TO_TEST:
            name = model_spec["name"]
            try:
                analyzer = SemanticNoveltyAnalyzer(model_name=name)
                score = analyzer.compute_novelty_score(invention_text, prior_art_texts)
                results[model_spec["type"]] = {
                    "model_name": name,
                    "novelty_index": score["novelty_index"],
                    "mean_similarity": score["mean_similarity"],
                    "max_similarity": score["max_similarity"],
                    "backend": score["backend"],
                    "loaded": analyzer.is_real_model(),
                }
            except Exception as exc:
                results[model_spec["type"]] = {
                    "model_name": name,
                    "error": str(exc),
                    "loaded": False,
                }

        # Generate benchmark report
        report_lines = []
        for model_type, data in results.items():
            if "error" in data:
                report_lines.append(f"{model_type}: ERROR - {data['error']}")
            else:
                report_lines.append(
                    f"{model_type} ({data['model_name']}): "
                    f"Novelty={data['novelty_index']:.1f}%, "
                    f"MeanSim={data['mean_similarity']:.4f}, "
                    f"Loaded={'Yes' if data['loaded'] else 'No (fallback)'}"
                )

        return {
            "models_tested": len(cls.MODELS_TO_TEST),
            "results": results,
            "report": "\n".join(report_lines),
            "timestamp": datetime.utcnow().isoformat(),
            "invention_text_length": len(invention_text),
            "n_prior_art": len(prior_art_texts),
        }


class CybersecurityHardening:
    """
    FIX 13: Cybersecurity hardening.
    - safe_eval wrapper (forbids dangerous eval/exec)
    - safe_literal_eval (uses ast.literal_eval)
    - Code scanner that flags dangerous patterns
    """

    DANGEROUS_PATTERNS = [
        # FIX v7.8 DEF-16: \beval\s*\( catches PyTorch model.eval() as false positive.
        # Fixed: require eval( at start of statement or after = (assignment), not after dot.
        (r"(?<![.\w])eval\s*\(", "Built-in eval() is forbidden — use ast.literal_eval for literals. Note: model.eval() (PyTorch) is safe and NOT flagged."),
        (r"(?<![.\w])exec\s*\(", "Built-in exec() is forbidden"),
        (r"__import__\s*\(", "__import__ is forbidden"),
        (r"os\.system\s*\(", "os.system is forbidden — use subprocess with explicit args"),
        (r"subprocess\..*shell\s*=\s*True", "shell=True is forbidden — security risk"),
        (r"pickle\.loads\b", "pickle.loads is forbidden — use json or safe format"),
        (r"yaml\.load\s*\([^)]*\)\s*$", "yaml.load without Loader is forbidden — use yaml.safe_load"),
    ]

    @staticmethod
    def safe_literal_eval(s: str) -> Any:
        """Safely evaluate a literal expression. Use instead of eval()."""
        return ast.literal_eval(s)

    @staticmethod
    def safe_eval(s: str, allowed_names: Optional[Dict[str, Any]] = None) -> Any:
        """
        Safe arithmetic expression evaluator.
        Only allows: numbers, +, -, *, /, **, %, (), and allowed_names.
        """
        allowed_names = allowed_names or {}
        # AST-based safe evaluation
        try:
            tree = ast.parse(s, mode="eval")
        except SyntaxError as e:
            raise ValueError(tr("err.invalid_expression", e=e))
        allowed_nodes = (
            ast.Expression, ast.BinOp, ast.UnaryOp, ast.Num, ast.Constant,
            ast.Add, ast.Sub, ast.Mult, ast.Div, ast.Pow, ast.Mod,
            ast.USub, ast.UAdd, ast.Name, ast.Load
        )
        for node in ast.walk(tree):
            if not isinstance(node, allowed_nodes):
                raise ValueError(tr("err.forbidden_node_type", type=type(node).__name__))
            if isinstance(node, ast.Name) and node.id not in allowed_names:
                raise ValueError(tr("err.variable_not_allowed", name=node.id))
        return eval(compile(tree, "<safe_eval>", "eval"), {"__builtins__": {}}, allowed_names)

    @classmethod
    def scan_code_for_vulnerabilities(cls, source_code: str) -> Dict[str, Any]:
        """Scan Python source for dangerous patterns. Returns list of findings."""
        findings = []
        # Strip docstrings and string literals using AST
        try:
            tree = ast.parse(source_code)
            # Collect line ranges of docstrings
            docstring_lines = set()
            for node in ast.walk(tree):
                if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef, ast.Module)):
                    if (node.body and isinstance(node.body[0], ast.Expr) and
                            isinstance(node.body[0].value, (ast.Constant, ast.Str))):
                        ds = node.body[0]
                        for ln in range(ds.lineno, ds.end_lineno + 1 if hasattr(ds, 'end_lineno') else ds.lineno + 1):
                            docstring_lines.add(ln)
            # Collect line ranges of all string literals
            string_lines = set()
            for node in ast.walk(tree):
                if isinstance(node, ast.Constant) and isinstance(node.value, str):
                    start = getattr(node, 'lineno', 0)
                    end = getattr(node, 'end_lineno', start) or start
                    for ln in range(start, end + 1):
                        string_lines.add(ln)
            skip_lines = docstring_lines | string_lines
        except SyntaxError:
            skip_lines = set()
        lines = source_code.split("\n")
        for line_no, line in enumerate(lines, start=1):
            stripped = line.strip()
            if line_no in skip_lines:
                continue
            # Skip comments
            if stripped.startswith("#"):
                continue
            # Skip PyTorch model.eval() — false positive (method call on object)
            if re.search(r"\w+\.eval\s*\(\s*\)", stripped):
                continue
            # Skip lines that are part of regex pattern strings (already in skip_lines)
            for pattern, message in cls.DANGEROUS_PATTERNS:
                if re.search(pattern, stripped):
                    # Extra check: if pattern is `eval(` but it's a method call like `obj.eval()`
                    if "eval" in pattern and re.search(r"\w+\.eval\s*\(", stripped):
                        continue
                    findings.append({
                        "line_number": line_no,
                        "line_content": stripped,
                        "pattern": pattern,
                        "message": message,
                        "severity": "high" if "eval" in pattern or "exec" in pattern else "medium",
                    })
        return {
            "total_findings": len(findings),
            "findings": findings,
            "scan_timestamp": _utc_now_iso(),
            "scanned_lines": len(lines),
            "skipped_lines_docstrings_and_strings": len(skip_lines),
            "safe": len(findings) == 0,
        }


class MerkleAuditChain:
    """
    FIX 14: Merkle hash chain for tamper-evident audit trail.
    - SHA-256 binary Merkle tree
    - Block hash links previous block hash
    - WORM (Write-Once-Read-Many) SQLite triggers
    - Tamper-evidence: any modification breaks the chain
    """

    def __init__(self, db_path: Union[str, Path] = DEFAULT_AUDIT_CHAIN_DB):
        self.db_path = str(db_path)
        self._init_db()

    def _init_db(self) -> None:
        Path(self.db_path).parent.mkdir(parents=True, exist_ok=True)
        with sqlite3.connect(self.db_path) as conn:
            conn.executescript("""
                CREATE TABLE IF NOT EXISTS audit_chain (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    previous_hash TEXT NOT NULL,
                    block_hash TEXT NOT NULL,
                    merkle_root TEXT NOT NULL,
                    payload TEXT NOT NULL,
                    timestamp TEXT NOT NULL,
                    actor TEXT NOT NULL,
                    signature TEXT
                );
                -- WORM protection: forbid UPDATE and DELETE
                CREATE TRIGGER IF NOT EXISTS prevent_audit_update
                BEFORE UPDATE ON audit_chain
                BEGIN
                    SELECT RAISE(FAIL, 'Audit chain is immutable (WORM protection)');
                END;
                CREATE TRIGGER IF NOT EXISTS prevent_audit_delete
                BEFORE DELETE ON audit_chain
                BEGIN
                    SELECT RAISE(FAIL, 'Audit chain is immutable (WORM protection)');
                END;
            """)

    def append(self, payload: Dict[str, Any], actor: str = "system") -> Dict[str, Any]:
        """Append a new block to the audit chain."""
        payload_str = _safe_json_dumps(payload)
        timestamp = _utc_now_iso()
        with sqlite3.connect(self.db_path) as conn:
            cursor = conn.cursor()
            cursor.execute("SELECT block_hash FROM audit_chain ORDER BY id DESC LIMIT 1")
            row = cursor.fetchone()
            previous_hash = row[0] if row else "0" * 64
            # Block hash = SHA256(prev_hash || timestamp || actor || payload)
            block_data = f"{previous_hash}|{timestamp}|{actor}|{payload_str}"
            block_hash = _sha256_str(block_data)
            # Merkle root for single block = block_hash itself
            merkle_root = block_hash
            # Sign with persistent key
            signature = ""
            try:
                sig_result = PersistentKeyManager.sign_with_persistent_key(block_data.encode("utf-8"))
                signature = sig_result["signature"]
            except Exception as exc:
                logger.warning(f"Signing failed: {exc}")
            cursor.execute("""
                INSERT INTO audit_chain (previous_hash, block_hash, merkle_root, payload, timestamp, actor, signature)
                VALUES (?, ?, ?, ?, ?, ?, ?)
            """, (previous_hash, block_hash, merkle_root, payload_str, timestamp, actor, signature))
            block_id = cursor.lastrowid
            conn.commit()
        return {
            "block_id": int(block_id),
            "previous_hash": previous_hash,
            "block_hash": block_hash,
            "merkle_root": merkle_root,
            "timestamp": timestamp,
            "actor": actor,
            "signature_provided": bool(signature),
        }

    def verify_chain(self) -> Dict[str, Any]:
        """Verify the integrity of the entire chain."""
        with sqlite3.connect(self.db_path) as conn:
            cursor = conn.cursor()
            cursor.execute("SELECT id, previous_hash, block_hash, payload, timestamp, actor FROM audit_chain ORDER BY id")
            rows = cursor.fetchall()
        if not rows:
            return {"valid": True, "n_blocks": 0, "tampered_blocks": []}
        tampered = []
        prev_hash = "0" * 64
        for row in rows:
            block_id, stored_prev, stored_hash, payload, timestamp, actor = row
            expected_prev = prev_hash
            expected_hash = _sha256_str(f"{expected_prev}|{timestamp}|{actor}|{payload}")
            if stored_prev != expected_prev or stored_hash != expected_hash:
                tampered.append({
                    "block_id": int(block_id),
                    "issue": "previous_hash_mismatch" if stored_prev != expected_prev else "block_hash_mismatch",
                })
            prev_hash = stored_hash
        return {
            "valid": len(tampered) == 0,
            "n_blocks": int(len(rows)),
            "tampered_blocks": tampered,
            "verification_timestamp": _utc_now_iso(),
        }


